public int minInsertions(String s) {
    int left = 0, res = 0;
    int n = s.length();
    for (int i = 0; i < n; i++) {
        if (s.charAt(i) == '(') {
            left++;
        } else {
            if (left == 0) res++;
            else left--;
            if (i == n - 1 || s.charAt(i + 1) != ')') {
                res++;
                i++;
            }
        }
    }
    return res + left * 2;
}
```

